/**
 * MONEYLAN Agent 2 — Linkfinder
 * Läuft im n8n Code-Node (Run Once for Each Item), nach dem Startseiten-Scrape.
 *
 * Findet im Startseiten-HTML die wichtigsten internen Unterseiten (Impressum, Menü,
 * Über-uns, Kontakt) und gibt die Startseite + bis zu 4 Unterseiten als EINZELNE Items
 * zurück, jeweils mit lead_id versehen. Der nachfolgende Oxylabs-HTTP-Node scrapt alle.
 *
 * INPUT ($json): lead_id, business{website,...}, score, html (Startseite), final_url
 * OUTPUT: Array von Items, jedes { lead_id, score, business, url, is_start, page_type }
 */

function normalizeUrl(href, baseUrl) {
  try {
    return new URL(href, baseUrl).href.split('#')[0];
  } catch (e) { return null; }
}

function sameDomain(url, baseUrl) {
  try {
    return new URL(url).hostname.replace(/^www\./, '') === new URL(baseUrl).hostname.replace(/^www\./, '');
  } catch (e) { return false; }
}

// Schlüsselseiten nach Priorität. Jede Kategorie max. 1 Treffer.
const CATEGORIES = [
  { type: 'impressum',  re: /impressum|imprint|kontakt|contact/i },
  { type: 'menue',      re: /speisekarte|speisen|men[uü]|karte|gerichte|essen/i },
  { type: 'ueber_uns',  re: /[uü]ber[\s_-]?uns|about|philosophie|geschichte|team|wir[\s_-]?[uü]ber/i },
  { type: 'datenschutz',re: /datenschutz|privacy/i }
];

function findKeyPages(html, baseUrl) {
  const links = [];
  const re = /<a\b[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi;
  let m;
  while ((m = re.exec(html)) !== null) {
    const href = m[1];
    const anchorText = m[2].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    const abs = normalizeUrl(href, baseUrl);
    if (!abs) continue;
    if (!sameDomain(abs, baseUrl)) continue;
    if (/\.(jpg|jpeg|png|gif|webp|svg|pdf|zip|mp4|css|js|ico)$/i.test(abs)) continue;
    links.push({ url: abs, text: anchorText, href });
  }

  const chosen = [];
  const usedUrls = new Set([normalizeUrl(baseUrl, baseUrl)]);
  for (const cat of CATEGORIES) {
    // Treffer: Schlüsselwort im Anchor-Text ODER im href/URL-Pfad
    const hit = links.find(l =>
      !usedUrls.has(l.url) && (cat.re.test(l.text) || cat.re.test(l.href))
    );
    if (hit) {
      chosen.push({ url: hit.url, page_type: cat.type });
      usedUrls.add(hit.url);
    }
    if (chosen.length >= 4) break;
  }
  return chosen;
}

function buildItems(input) {
  const baseUrl = input.final_url || input.business?.website;
  const html = String(input.html || '');
  const keyPages = baseUrl ? findKeyPages(html, baseUrl) : [];

  const common = { lead_id: input.lead_id, score: input.score, business: input.business };

  const items = [
    { ...common, url: baseUrl, is_start: true, page_type: 'startseite' }
  ];
  for (const p of keyPages) {
    items.push({ ...common, url: p.url, is_start: false, page_type: p.page_type });
  }
  // n8n erwartet [{json:...}, ...] bei runOnceForEachItem mit Mehrfach-Output:
  return items;
}

if (typeof module !== 'undefined' && module.exports) {
  module.exports = { buildItems, findKeyPages, normalizeUrl, sameDomain };
}

// In n8n (Run Once for Each Item, return array): return buildItems($json).map(i => ({ json: i }));


return buildItems($json).map(i => ({ json: i }));

// Alle Seiten-Items dieses Loop-Durchlaufs gehoeren zum selben Lead.
const items = $input.all();
if (!items.length) return [];

// Lead-Stammdaten: aus erstem Item ODER aus Prep Startseite (Fallback, da Oxylabs die Metadaten nicht durchreicht)
const first = items[0].json;
const lead_id = first.lead_id || $('Prep Startseite').first().json.lead_id || null;
const business = first.business || $('Prep Startseite').first().json.business || {};
const score = (first.score !== undefined) ? first.score : ($('Prep Startseite').first().json.score || 0);

// Startseiten-URL als final_url bevorzugen
let final_url = business?.website || '';
let combined = '';
for (const it of items) {
  const j = it.json;
  const content = j.data || j.results?.[0]?.content || '';
  const ptype = j.page_type || 'seite';
  if (j.is_start) final_url = j.url || business?.website || final_url;
  if (content) {
    combined += `\n<!-- ==== SEITE: ${ptype} (${j.url || final_url}) ==== -->\n` + content;
  }
}

return [{ json: { lead_id, score, business, final_url, html: combined } }];

function cleanUrl(value) {
  let url = String(value || '').trim();

  // unsichtbare Zeichen und Leerzeichen entfernen
  url = url.replace(/[\u200B-\u200D\uFEFF]/g, '');
  url = url.replace(/\s+/g, '');

  if (!url) return null;

  // falls nur domain.de drinsteht
  if (!/^https?:\/\//i.test(url)) {
    url = 'https://' + url;
  }

  return url;
}

const r = $json;

return {
  lead_id: String(r.lead_id || '').trim(),
  score: Number(r.score || 0),
  business: {
    name: r.name ? String(r.name).trim() : null,
    website: cleanUrl(r.website),
    place_id: r.place_id ? String(r.place_id).trim() : null,
    phone: r.phone ? String(r.phone).trim() : null,
    address: r.address ? String(r.address).trim() : null,
    google_rating: r.google_rating ? Number(r.google_rating) : null,
    google_reviews_count: r.google_reviews ? Number(r.google_reviews) : null
  }
};

/**
 * MONEYLAN Agent 2 — Roh-Text-Extraktion
 * Läuft im n8n Code-Node (Run Once for Each Item), VOR dem LLM-Node.
 *
 * ERWARTETER INPUT pro Item ($json):
 *   business: { name, website, place_id, phone, address, ... }   (aus Agent 1)
 *   score:    number                                             (aus Agent 1)
 *   lead_id:  string
 *   html:     string  (Startseiten-HTML, frisch über Oxylabs geholt)
 *   final_url:string
 *
 * OUTPUT pro Item: Roh-Felder + bereinigter Volltext, die der LLM-Node dann strukturiert.
 *
 * Deterministisch, kein LLM. JSON-LD zuerst, Fließtext als Fallback.
 */

// ---------- Hilfsfunktionen ----------

function stripTags(html) {
  return String(html || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ');
}

function decodeEntities(s) {
  return String(s || '')
    .replace(/&nbsp;/gi, ' ').replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"').replace(/&#0?39;|&apos;/gi, "'")
    .replace(/&lt;/gi, '<').replace(/&gt;/gi, '>')
    .replace(/&auml;/gi, 'ä').replace(/&ouml;/gi, 'ö').replace(/&uuml;/gi, 'ü')
    .replace(/&Auml;/gi, 'Ä').replace(/&Ouml;/gi, 'Ö').replace(/&Uuml;/gi, 'Ü')
    .replace(/&szlig;/gi, 'ß').replace(/&#(\d+);/g, (_, n) => String.fromCharCode(+n));
}

function collapse(s) {
  return decodeEntities(String(s || '')).replace(/\s+/g, ' ').trim();
}

// ---------- JSON-LD (schema.org) ----------

function extractJsonLd(html) {
  const blocks = [];
  const re = /<script[^>]+type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
  let m;
  while ((m = re.exec(html)) !== null) {
    try {
      const parsed = JSON.parse(m[1].trim());
      if (Array.isArray(parsed)) blocks.push(...parsed);
      else if (parsed['@graph']) blocks.push(...parsed['@graph']);
      else blocks.push(parsed);
    } catch (e) { /* defektes JSON-LD ignorieren */ }
  }
  return blocks;
}

function pickBusinessNode(blocks) {
  // Bevorzugt Restaurant/FoodEstablishment/LocalBusiness/Organization
  const prio = ['Restaurant', 'FoodEstablishment', 'CafeOrCoffeeShop', 'BarOrPub',
                'LocalBusiness', 'Organization'];
  for (const t of prio) {
    const hit = blocks.find(b => {
      const type = b['@type'];
      return type === t || (Array.isArray(type) && type.includes(t));
    });
    if (hit) return hit;
  }
  return blocks[0] || null;
}

function formatOpeningHours(node) {
  // schema.org: openingHours (string|array) oder openingHoursSpecification (array of obj)
  if (node.openingHours) {
    return Array.isArray(node.openingHours) ? node.openingHours.join('; ') : String(node.openingHours);
  }
  const spec = node.openingHoursSpecification;
  if (Array.isArray(spec)) {
    return spec.map(s => {
      const d = Array.isArray(s.dayOfWeek) ? s.dayOfWeek.join(',') : (s.dayOfWeek || '');
      const day = String(d).replace(/https?:\/\/schema\.org\//g, '');
      return `${day} ${s.opens || ''}-${s.closes || ''}`.trim();
    }).join('; ');
  }
  return null;
}

function addrToString(addr) {
  if (!addr) return null;
  if (typeof addr === 'string') return collapse(addr);
  const p = [addr.streetAddress, addr.postalCode, addr.addressLocality, addr.addressRegion]
    .filter(Boolean).join(', ');
  return p || null;
}

function extractMenuFromJsonLd(blocks, node) {
  const items = [];
  const collect = (menu) => {
    const sections = menu.hasMenuSection
      ? (Array.isArray(menu.hasMenuSection) ? menu.hasMenuSection : [menu.hasMenuSection])
      : [];
    for (const sec of sections) {
      const its = sec.hasMenuItem
        ? (Array.isArray(sec.hasMenuItem) ? sec.hasMenuItem : [sec.hasMenuItem])
        : [];
      for (const it of its) {
        const price = it.offers && (it.offers.price || (Array.isArray(it.offers) && it.offers[0]?.price));
        items.push(collapse([it.name, it.description, price ? `(${price})` : ''].filter(Boolean).join(' — ')));
      }
    }
  };
  const menuBlocks = blocks.filter(b => {
    const t = b['@type'];
    return t === 'Menu' || (Array.isArray(t) && t.includes('Menu'));
  });
  menuBlocks.forEach(collect);
  if (node && node.hasMenu && typeof node.hasMenu === 'object') collect(node.hasMenu);
  return items;
}

// ---------- Meta-Tags ----------

function metaContent(html, key, attr) {
  // attr = 'property' (og:) oder 'name'
  const re = new RegExp(`<meta[^>]+${attr}=["']${key}["'][^>]*content=["']([^"']*)["']`, 'i');
  const m = html.match(re);
  if (m) return collapse(m[1]);
  // andere Attribut-Reihenfolge
  const re2 = new RegExp(`<meta[^>]+content=["']([^"']*)["'][^>]*${attr}=["']${key}["']`, 'i');
  const m2 = html.match(re2);
  return m2 ? collapse(m2[1]) : null;
}

// ---------- E-Mail + Social ----------

function extractEmail(html) {
  // mailto zuerst (verlässlichster), dann Text-Regex
  const mailto = html.match(/mailto:([^"'?>\s]+)/i);
  if (mailto) return mailto[1].toLowerCase();
  const txt = stripTags(html);
  const m = txt.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/i);
  if (m) {
    const e = m[0].toLowerCase();
    // offensichtliche Platzhalter/Bilddateien aussortieren
    if (!/\.(png|jpg|jpeg|gif|webp|svg)$/i.test(e) && !/example\.(com|org)/.test(e)) return e;
  }
  return null;
}

function extractSocial(html) {
  const patterns = {
    facebook: /https?:\/\/(?:www\.)?facebook\.com\/[A-Za-z0-9._%-]+/i,
    instagram: /https?:\/\/(?:www\.)?instagram\.com\/[A-Za-z0-9._%-]+/i,
    twitter: /https?:\/\/(?:www\.)?(?:twitter|x)\.com\/[A-Za-z0-9._%-]+/i,
    tiktok: /https?:\/\/(?:www\.)?tiktok\.com\/@[A-Za-z0-9._%-]+/i,
    youtube: /https?:\/\/(?:www\.)?youtube\.com\/[A-Za-z0-9@._%/-]+/i,
    linkedin: /https?:\/\/(?:www\.)?linkedin\.com\/[A-Za-z0-9._%/-]+/i
  };
  const out = [];
  for (const [name, re] of Object.entries(patterns)) {
    const m = html.match(re);
    if (m) out.push({ platform: name, url: m[0] });
  }
  return out;
}

// ---------- Telefon ----------

function extractPhone(html, fallback) {
  const tel = html.match(/tel:([+0-9()\/\s-]{6,})/i);
  if (tel) return collapse(tel[1]);
  return fallback || null;
}

// ---------- Sichtbarer Fließtext + Überschriften ----------

function extractHeadings(html) {
  const out = [];
  const re = /<h([1-3])[^>]*>([\s\S]*?)<\/h\1>/gi;
  let m;
  while ((m = re.exec(html)) !== null) {
    const txt = collapse(stripTags(m[2]).replace(/<[^>]+>/g, ' '));
    if (txt && txt.length > 1 && txt.length < 200) out.push({ level: +m[1], text: txt });
  }
  return out.slice(0, 40);
}

function extractVisibleText(html) {
  // Boilerplate-Container grob entfernen, dann Tags strippen
  let h = stripTags(html);
  h = h.replace(/<(nav|footer|header)[\s\S]*?<\/\1>/gi, ' ');
  // Block-Elemente in Zeilenumbrüche wandeln, damit Wörter nicht verkleben
  h = h.replace(/<\/(p|div|li|h[1-6]|br|tr|section)[^>]*>/gi, '\n').replace(/<br[^>]*>/gi, '\n');
  h = h.replace(/<[^>]+>/g, ' ');
  h = decodeEntities(h);
  // Zeilen säubern, sehr kurze/Menü-artige Fragmente bündeln
  const lines = h.split(/\n+/).map(l => l.replace(/\s+/g, ' ').trim()).filter(l => l.length > 1);
  // Duplikate raus, Reihenfolge erhalten
  const seen = new Set();
  const uniq = [];
  for (const l of lines) {
    const k = l.toLowerCase();
    if (!seen.has(k)) { seen.add(k); uniq.push(l); }
  }
  const full = uniq.join('\n');
  // auf vernünftige Länge für LLM begrenzen (Anfang ist am wichtigsten)
  return full.length > 12000 ? full.slice(0, 12000) + '\n…[gekürzt]' : full;
}

// ---------- Hauptfunktion ----------

function extractRaw(input) {
  const business = input.business || {};
  const html = String(input.html || '');

  const blocks = extractJsonLd(html);
  const node = pickBusinessNode(blocks);

  const jsonld = {
    name: node ? collapse(node.name) : null,
    description: node ? collapse(node.description) : null,
    address: node ? addrToString(node.address) : null,
    opening_hours: node ? formatOpeningHours(node) : null,
    cuisine: node && node.servesCuisine
      ? (Array.isArray(node.servesCuisine) ? node.servesCuisine : [node.servesCuisine]).map(collapse)
      : [],
    price_range: node ? (node.priceRange || null) : null,
    telephone: node ? (node.telephone || null) : null,
    menu: extractMenuFromJsonLd(blocks, node)
  };

  const og = {
    title: metaContent(html, 'og:title', 'property'),
    description: metaContent(html, 'og:description', 'property'),
    site_name: metaContent(html, 'og:site_name', 'property')
  };
  const metaDesc = metaContent(html, 'description', 'name');
  const titleTag = (html.match(/<title[^>]*>([\s\S]*?)<\/title>/i) || [])[1];

  const email = extractEmail(html);
  const social = extractSocial(html);
  const phone = jsonld.telephone || extractPhone(html, business.phone);

  return {
    // Pass-through für spätere Nodes
    lead_id: input.lead_id || null,
    score: input.score != null ? input.score : null,
    source_url: input.final_url || business.website || null,
    business_name_hint: business.name || null,
    address_hint: business.address || null,

    // verlässliche Roh-Fakten (für Merge nach dem LLM)
    raw_facts: {
      name: jsonld.name || og.site_name || og.title || collapse(titleTag) || business.name || null,
      address: jsonld.address || business.address || null,
      opening_hours: jsonld.opening_hours || null,
      telephone: phone || null,
      email: email || null,
      social: social,
      cuisine: jsonld.cuisine,
      price_range: jsonld.price_range,
      menu_jsonld: jsonld.menu
    },

    // Quellen-Material für den LLM
    meta: { title_tag: collapse(titleTag), meta_description: metaDesc, og },
    jsonld_description: jsonld.description,
    headings: extractHeadings(html),
    visible_text: extractVisibleText(html),

    extraktion_quellen: {
      json_ld: blocks.length > 0,
      json_ld_business: !!node,
      fliesstext: true
    }
  };
}

if (typeof module !== 'undefined' && module.exports) {
  module.exports = { extractRaw, extractJsonLd, extractEmail, extractSocial, extractVisibleText };
}

// In n8n: return extractRaw($json);


return extractRaw($json);

